INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-57f41407-moex-00423', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「老闆總是告訴我們要『像海綿一樣地吸收』，但在2020年，可能還沒累積什麼有用的東西，這塊海 綿就已經充滿細菌，因為在使用網路和智慧型手機已經像呼吸一樣自然的時代，每天流動在眼前的資 訊有無限多，選項已經由外部決定轉變為內部篩選，所以我們不會去問YouTube有什麼可以看？而是 得告訴YouTube我想看什麼，或是我不想看什麼。」 下列何者思想最能夠幫助我們理解這段話的意旨？', '["《論語》：非禮勿視，非禮勿聽，非禮勿言，非禮勿動", "《老子》：為學日益，為道日損。損之又損，以至於無為。無為而無不為", "《荀子》：學不可以已。青，取之於藍，而青於藍；冰，水為之，而寒於水", "《墨子》：欲求興天下之利，除天下之害，當在樂之為物，將不可不禁而止也"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00424', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '哭泣計有兩類：一為有力類，一為無力類。癡兒騃女，失果則啼，遺簪亦泣，此為無力類之哭泣；城 崩杞婦之哭，竹染湘妃之淚，此有力類之哭泣也。有力類之哭泣又分兩種：以哭泣為哭泣者，其力尚 弱；不以哭泣為哭泣者，其力甚勁，其行乃彌遠也。（劉鶚《老殘遊記》） 根據上文，下列選項何者符合作者的觀點？', '["認為哭泣的原因可分兩類", "哭泣是一種情緒的抒發，有益健康", "失髮簪而哭，跟杞婦哭到城牆崩壞，都屬於無力之哭", "不以哭泣的形式來表達哭泣的心情，其力道最大，影響也最深"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00425', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '錐入地，上有小笋，安長二尺餘木槽，可以隨隅轉移。約寬二寸，以容水，兩頭浮木鴨，謂之水平。 一匠持尺墨於隅牆，一匠於水平旁斜倚木杖，隻眼視鴨。覆其手，則持尺之匠移下；翻其手，則持尺 之匠移上；與鴨平則揮手。（李光庭《鄉言解頤》） 上文在描述古人從事何種工作？', '["馴養水鴨之法", "蓋房測量水平", "擇墓探勘風水", "準備繪製壁畫"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00426', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '謝公夫人教兒，問太傅（謝安）：「那得初不見君教兒？」答曰：「我常自教兒。」（《世說新語》） 謝公即謝安，他的回答主要在說明：', '["自己以身作則", "夫妻同心一體", "教兒時妻子未見", "夫妻之分工有別"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00427', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '專制之朝，病在壅塞，言路通則壅塞去矣。立憲之國，萬機決於公論，議院之外，又有報紙，為民口 之機關，壅塞之病似可決矣。乃有所謂殖民地者，既無議院，又乏輿論代表機關，即有一二報紙，皆 仰官僚鼻息，擁護一部，抑制多數，而各圖其私，是非顛倒。（謝國文〈神鍼法炙其三〉） 根據上文，下列何者錯誤？', '["一言堂是專制政權的常態", "報紙是殖民地輿論的暢通管道", "當政者宜廣開言路，不可專制獨裁", "憲政體制的國家，政府施政取決於公議"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00428', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '王梵志詩：「他人騎大馬，我獨跨驢子。回顧擔柴漢，心下較些子。」下列選項，與本詩旨趣最相近的是：', '["澹泊以明志", "寧靜而致遠", "知足心常泰", "無求品自高"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00429', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '下列詩句，何者最能抒發「世事常常不順人意」之感？', '["書冊埋頭無了日，不如拋卻去尋春", "書當快意讀易盡，客有可人期不來", "書中自有黃金屋，書中自有顏如玉", "書有未曾經我讀，事無不可對人言"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00430', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '臨皐亭下不數十步，便是大江，其半是峨眉雪水，吾飲食沐浴皆取焉，何必歸鄉哉！江山風月，本無 常主，閒者便是主人。問范子豐新第園池，與此孰勝？（蘇軾〈與范子豐〉） 根據上文，作者認為自己不必歸鄉的原因，最適合的是：', '["目前居住的臨皐亭與家鄉距離甚近", "大江與故鄉相連，時時可聞故鄕訊息", "既然暫時無法回鄉，不妨就把他鄉當作故鄉", "居住於臨皐亭的作者樂不思蜀，故不急於返鄉"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00431', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '承上題，下列對於「江山風月，本無常主，閒者便是主人」的闡釋，最適合的是：', '["美好的江山風月，常隨政權易主，難以永遠擁有", "只有無事可做的閒人，才會成天遊山玩水，不事生產", "只有身心安閒、能領受天地之美的人，才能擁有眼前的江山風月", "能擁有廣大園林的人，通常皆已功成名就，不必再為生活汲汲營營"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00432', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '下列成語使用正確的是：', '["遇到難題時，他總是「不恥下問」地請教專家", "雖然這次比賽結果「差強人意」，但我已盡了全力", "進行科學發明，要勇於創新，立志成為「始作俑者」", "從小父母對我「耳提面命」，諄諄告誡許多待人接物的道理 野柳的地質景觀女王頭，外型「巧奪天工」，宛如一位凝視遠方的女王"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
